import { useNavigate } from "react-router-dom";

export default function Navbar(){
  const nav = useNavigate();

  const logout = ()=>{
    localStorage.clear();
    nav("/");
  }

  return(
    <div style={styles.nav}>
      <h3>DailyWorker</h3>

      <div>
        <button onClick={()=>nav("/customer")}>Customer</button>
        <button onClick={()=>nav("/labour")}>Labour</button>
        <button onClick={logout}>Logout</button>
      </div>
    </div>
  )
}

const styles={
  nav:{
    display:"flex",
    justifyContent:"space-between",
    padding:"10px",
    background:"#f5f5f5",
    borderBottom:"1px solid #ddd"
  }
}
